        LEERNESS_ENABLE_GOOSE: enable('goose') ? '1' : '0',
        LEERNESS_ENABLE_COPILOT: enable('copilot') ? '1' : '0',
        LEERNESS_ENABLE_OLLAMA: enable('ollama') ? '1' : '0',
        LEERNESS_SKILL_DISCOVER_URL: '',
