  log(t(`  런타임 의존성: ${deps.length === 0 ? '0건 (외부 패키지 없음 — 공급망 노출 0)' : deps.length + '건 — ' + deps.join(', ')}`, `  runtime deps: ${deps.length === 0 ? '0 (no external packages — zero supply-chain exposure)' : deps.length + ' — ' + deps.join(', ')}`));
